+        );
+        assert!(registry.check(&FabricCapability::CreateStream {
+            subject: acme_orders.namespace().durable_capture_pattern(),
+        }));
+        assert!(!registry.check(&FabricCapability::CreateStream {
+            subject: bravo_orders.durable_capture_pattern(),
+        }));
